/**
 * BootSequence — faithful vanilla-JS port of the RAY-SPY React (.tsx) boot
 * intro: laser draw → explosion → globe + hologram logo → title + HUD →
 * status sync → dashboard handoff.
 *
 * NOTE ON ASSETS
 * The original .tsx imported two local project assets that don't exist
 * outside that codebase:
 *   - earthTexture  (assets/earth-texture.jpg)
 *   - logoAsset     (assets/ray-spy-symbol.png)
 * Point CONFIG.earthTextureUrl / CONFIG.logoImageUrl at your own files to
 * get pixel-identical output. Leaving logoImageUrl as null falls back to a
 * built-in inline SVG mark styled the same way (red → cyan hologram flip).
 */

const CONFIG = {
  earthTextureUrl: 'https://eoimages.gsfc.nasa.gov/images/imagerecords/57000/57752/land_shallow_topo_2048.jpg',
  logoImageUrl: 'data:image/png;base64,',
};

export function mountBootSequence(onEnter) {
  if (new URLSearchParams(location.search).has('skipBoot')) {
    onEnter();
    return;
  }

  injectCSS();

  const root = document.createElement('div');
  root.id = 'rsp-boot';
  root.innerHTML = `
    <div class="rsp-scanline-overlay"></div>
    <div class="rsp-vignette-overlay"></div>

    <canvas id="rsp-boot-canvas" class="rsp-boot-canvas"></canvas>

    <!-- Globe -->
    <div class="rsp-globe-wrap" id="rsp-globe-wrap">
      <div class="rsp-globe-sphere">
        <div class="rsp-earth-img" style="background-image:url('${CONFIG.earthTextureUrl}')"></div>
        <div class="rsp-globe-grid"></div>
        <div class="rsp-globe-rim"></div>
      </div>
      <div class="rsp-globe-outer-ring"></div>
      <div class="rsp-globe-outer-ring-dashed"></div>
    </div>

    <!-- Logo hologram -->
    <div class="rsp-logo-wrap" id="rsp-logo-wrap">
      ${logoMarkup()}
    </div>

    <!-- Targeting reticle (phase 1 only) -->
    <div class="rsp-reticle" id="rsp-reticle">
      <div class="rsp-reticle-box"></div>
      <div class="rsp-reticle-dot"></div>
      <span class="rsp-reticle-label">A-001</span>
    </div>

    <!-- Title -->
    <div class="rsp-boot-title-wrap" id="rsp-boot-title-wrap">
      <h1 class="rsp-boot-title">RAY-SPY</h1>
      <div class="rsp-boot-title-rule"></div>
    </div>

    <!-- Bottom status + progress -->
    <div class="rsp-boot-status" id="rsp-boot-status">
      <div class="rsp-boot-status-top">
        <span class="rsp-boot-label" id="rsp-boot-label">INITIALIZATING COMMAND SYSTEM</span>
        <span class="rsp-boot-pct" id="rsp-boot-pct">0%</span>
      </div>
      <div class="rsp-boot-bar-track">
        <div class="rsp-boot-bar-fill" id="rsp-boot-bar-fill"></div>
        <div class="rsp-boot-bar-ticks" id="rsp-boot-bar-ticks"></div>
      </div>
      <div class="rsp-boot-status-bottom">
        <span id="rsp-boot-sys">SYS//0.0x</span>
        <span id="rsp-boot-ch">CH-0</span>
        <span>OK</span>
      </div>
    </div>

    <!-- HUD corner brackets (phase 4) -->
    <div class="rsp-hud-corner rsp-hud-tl"></div>
    <div class="rsp-hud-corner rsp-hud-tr"></div>
    <div class="rsp-hud-corner rsp-hud-bl"></div>
    <div class="rsp-hud-corner rsp-hud-br"></div>
  `;
  document.body.appendChild(root);

  const labelEl = root.querySelector('#rsp-boot-label');
  const pctEl   = root.querySelector('#rsp-boot-pct');
  const barEl   = root.querySelector('#rsp-boot-bar-fill');
  const sysEl   = root.querySelector('#rsp-boot-sys');
  const chEl    = root.querySelector('#rsp-boot-ch');
  const canvas  = root.querySelector('#rsp-boot-canvas');

  // ---------------------------------------------------------------------
  // Phase timeline — matches the .tsx timings exactly
  // ---------------------------------------------------------------------
  const timers = [];
  const t = (ms, fn) => timers.push(setTimeout(fn, ms));

  const EXPLOSION_MS = 2800; // laser detonates after the globe (2800ms) and title (4200ms) are already visible

  t(100,  () => root.classList.add('rsp-phase-1'));                        // laser draws
  t(2800, () => root.classList.add('rsp-phase-3'));                        // globe + logo + status
  t(4200, () => root.classList.add('rsp-phase-4'));                        // title + HUD + color shift
  t(EXPLOSION_MS, () => { root.classList.remove('rsp-phase-1'); root.classList.add('rsp-phase-2'); }); // explosion
  t(5600, () => { labelEl.textContent = 'SYNCING GLOBAL DATA'; root.classList.add('rsp-phase-5'); });
  t(7400, () => { labelEl.textContent = 'LOADING DASHBOARD'; root.classList.add('rsp-phase-6'); });
  t(9200, () => {
    root.classList.add('rsp-boot-exit');
    setTimeout(() => { cleanup(); root.remove(); onEnter(); }, 600);
  });

  // ---------------------------------------------------------------------
  // Progress bar — starts once the globe appears (phase 3), 6s ramp
  // ---------------------------------------------------------------------
  const PROGRESS_START = 2800;
  const PROGRESS_DURATION = 6000;
  const bootStart = performance.now();
  let progressRaf;

  function tickProgress(now) {
    const elapsed = now - bootStart;
    if (elapsed >= PROGRESS_START) {
      const p = Math.min(100, ((elapsed - PROGRESS_START) / PROGRESS_DURATION) * 100);
      pctEl.textContent = Math.round(p) + '%';
      barEl.style.width = p + '%';
      sysEl.textContent = `SYS//${Math.floor(p * 12)}.0x`;
      chEl.textContent = `CH-${Math.floor(p)}`;
    }
    if (elapsed < PROGRESS_START + PROGRESS_DURATION + 200) {
      progressRaf = requestAnimationFrame(tickProgress);
    }
  }
  progressRaf = requestAnimationFrame(tickProgress);

  // ---------------------------------------------------------------------
  // Canvas: laser draw + explosion particle burst (ported 1:1 from .tsx)
  // ---------------------------------------------------------------------
  const ctx = canvas.getContext('2d');
  let w = (canvas.width = window.innerWidth);
  let h = (canvas.height = window.innerHeight);
  const onResize = () => { w = canvas.width = window.innerWidth; h = canvas.height = window.innerHeight; };
  window.addEventListener('resize', onResize);

  const particles = [];
  let exploded = false;
  let laserWidth = 0;
  let canvasRaf;
  const canvasStart = performance.now();

  function spawnExplosion() {
    const cx = w / 2, cy = h / 2;
    for (let i = 0; i < 220; i++) {
      const a = Math.random() * Math.PI * 2;
      const sp = 6 + Math.random() * 22;
      const r = Math.random();
      const color =
        r < 0.5  ? 'rgba(0,235,255,'
        : r < 0.8  ? 'rgba(120,255,240,'
        : r < 0.92 ? 'rgba(255,255,255,'
        : 'rgba(255,60,90,';
      particles.push({
        x: cx, y: cy,
        vx: Math.cos(a) * sp, vy: Math.sin(a) * sp,
        life: 0, max: 80 + Math.random() * 70,
        color, size: 1.2 + Math.random() * 2.5,
      });
    }
    for (let i = 0; i < 50; i++) {
      const a = (Math.random() - 0.5) * 0.35;
      const sp = 14 + Math.random() * 22;
      const dir = Math.random() > 0.5 ? 1 : -1;
      particles.push({
        x: cx, y: cy,
        vx: Math.cos(a) * sp * dir, vy: Math.sin(a) * sp,
        life: 0, max: 50 + Math.random() * 30,
        color: 'rgba(255,50,80,', size: 1.5 + Math.random() * 2,
      });
    }
  }

  let lastT = performance.now();
  function drawCanvas(now) {
    const elapsed = now - canvasStart;
    const dt = Math.min(2.5, (now - lastT) / 16.666);
    lastT = now;
    ctx.clearRect(0, 0, w, h);

    // Laser progression: 100ms..1600ms => 0..1, then holds until EXPLOSION_MS
    laserWidth = Math.max(0, Math.min(1, (elapsed - 100) / 1500));
    if (!exploded && elapsed > EXPLOSION_MS) { exploded = true; spawnExplosion(); }

    if (laserWidth > 0) {
      const cy = h / 2;
      const half = (w / 2) * laserWidth;
      const fade = exploded ? Math.max(0, 1 - (elapsed - EXPLOSION_MS) / 700) : 1;

      ctx.save();
      ctx.globalCompositeOperation = 'lighter';
      const passes = [
        [60, 0.35 * fade, '#ff1030'],
        [24, 0.7 * fade, '#ff3050'],
        [8, 0.95 * fade, '#ff6080'],
      ];
      for (const [blur, alpha, color] of passes) {
        ctx.shadowBlur = blur;
        ctx.shadowColor = color;
        ctx.strokeStyle = color;
        ctx.lineWidth = blur === 8 ? 2 : blur === 24 ? 3 : 4;
        ctx.beginPath();
        ctx.globalAlpha = alpha;
        ctx.moveTo(w / 2 - half, cy);
        ctx.lineTo(w / 2 + half, cy);
        ctx.stroke();
      }
      ctx.shadowBlur = 12;
      ctx.shadowColor = '#fff';
      ctx.strokeStyle = '#fff';
      ctx.lineWidth = 1;
      ctx.globalAlpha = fade;
      ctx.beginPath();
      ctx.moveTo(w / 2 - half, cy);
      ctx.lineTo(w / 2 + half, cy);
      ctx.stroke();
      ctx.globalAlpha = 0.35 * fade;
      ctx.beginPath();
      ctx.moveTo(w / 2 - half, cy - 6);
      ctx.lineTo(w / 2 + half, cy - 6);
      ctx.stroke();
      ctx.restore();
    }

    ctx.save();
    ctx.globalCompositeOperation = 'lighter';
    const drag = Math.pow(0.992, dt);
    for (let i = particles.length - 1; i >= 0; i--) {
      const p = particles[i];
      p.life += dt;
      p.x += p.vx * dt;
      p.y += p.vy * dt;
      p.vx *= drag; p.vy *= drag;
      const lifeRatio = p.life / p.max;
      const a = Math.max(0, 1 - lifeRatio);
      const eased = a * a * (3 - 2 * a);
      const offscreen = p.x < -40 || p.x > w + 40 || p.y < -40 || p.y > h + 40;
      if (a <= 0 || offscreen) { particles.splice(i, 1); continue; }
      ctx.fillStyle = p.color + eased.toFixed(3) + ')';
      ctx.shadowBlur = 18;
      ctx.shadowColor = p.color + '1)';
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size * (0.6 + eased * 0.8), 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();

    if (exploded) {
      const ft = (elapsed - EXPLOSION_MS) / 450;
      if (ft < 1) {
        const flash = 1 - ft;
        ctx.save();
        const grad = ctx.createRadialGradient(w / 2, h / 2, 0, w / 2, h / 2, Math.hypot(w, h) / 2);
        grad.addColorStop(0, `rgba(255,255,255,${0.9 * flash})`);
        grad.addColorStop(0.2, `rgba(120,240,255,${0.6 * flash})`);
        grad.addColorStop(0.6, `rgba(0,120,200,${0.15 * flash})`);
        grad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, w, h);
        ctx.restore();
      }
    }

    canvasRaf = requestAnimationFrame(drawCanvas);
  }
  canvasRaf = requestAnimationFrame(drawCanvas);

  function cleanup() {
    timers.forEach(clearTimeout);
    if (progressRaf) cancelAnimationFrame(progressRaf);
    if (canvasRaf) cancelAnimationFrame(canvasRaf);
    window.removeEventListener('resize', onResize);
  }

  window.addEventListener('beforeunload', cleanup, { once: true });
}

function logoMarkup() {
  if (CONFIG.logoImageUrl) {
    return `<img src="${CONFIG.logoImageUrl}" alt="RAY-SPY" class="rsp-logo-img" />`;
  }
  // Fallback inline SVG mark (used when no logoImageUrl is configured)
  return `
    <svg viewBox="0 0 200 100" class="rsp-logo-svg" aria-hidden="true" style="background:transparent">
      <g fill="none" stroke="currentColor" stroke-width="4" stroke-linecap="round" stroke-linejoin="round">
        <path d="M 40,82 C 40,50 55,34 78,34 C 89,34 96,40 96,50 L 96,82"/>
        <path d="M 104,82 L 104,50 C 104,40 111,34 122,34 C 145,34 160,50 160,82"/>
        <path d="M 96,82 Q 100,90 104,82"/>
        <path d="M 40,82 Q 70,94 96,82"/>
        <path d="M 104,82 Q 130,94 160,82"/>
        <line x1="34" y1="24" x2="50" y2="24" stroke-width="2.4"/>
        <line x1="150" y1="24" x2="166" y2="24" stroke-width="2.4"/>
      </g>
    </svg>
  `;
}

function injectCSS() {
  if (document.getElementById('rsp-boot-css')) return;
  const s = document.createElement('style');
  s.id = 'rsp-boot-css';
  s.textContent = `
    @import url('https://fonts.googleapis.com/css2?family=Share+Tech+Mono&display=swap');

    #rsp-boot {
      position: fixed; inset: 0; z-index: 10000;
      background: #000;
      color: #fff;
      font-family: 'Share Tech Mono', ui-monospace, 'JetBrains Mono', 'Fira Code', monospace;
      overflow: hidden;
      transition: opacity 1s ease;
    }
    #rsp-boot.rsp-boot-exit { opacity: 0; pointer-events: none; }

    .rsp-scanline-overlay {
      position: absolute; inset: 0; z-index: 50;
      opacity: 0.3; mix-blend-mode: overlay; pointer-events: none;
      background-image: repeating-linear-gradient(0deg, rgba(255,255,255,0.06) 0 1px, transparent 1px 3px);
    }
    .rsp-vignette-overlay {
      position: absolute; inset: 0; z-index: 50; pointer-events: none;
      background: radial-gradient(ellipse at center, transparent 55%, rgba(0,0,0,0.85) 100%);
    }

    .rsp-boot-canvas {
      position: absolute; inset: 0;
      width: 100%; height: 100%;
      z-index: 10;
      pointer-events: none;
    }

    /* ---------------- Globe ---------------- */
    .rsp-globe-wrap {
      position: absolute; left: 50%; top: 50%;
      width: min(56vmin, 560px); height: min(56vmin, 560px);
      transform: translate(-50%, -50%) scale(0.5);
      opacity: 0;
      transition: opacity 1s ease, transform 1s ease;
      z-index: 1;
    }
    #rsp-boot.rsp-phase-3 .rsp-globe-wrap { opacity: 1; transform: translate(-50%, -50%) scale(1); }

    .rsp-globe-sphere {
      position: absolute; inset: 0; border-radius: 50%; overflow: hidden;
      background: radial-gradient(circle at 35% 35%, rgba(0,180,255,0.25), rgba(0,10,40,1) 70%);
      box-shadow:
        0 0 80px 20px rgba(0,140,255,0.35),
        0 0 200px 60px rgba(0,90,255,0.25),
        inset 0 0 80px rgba(0,200,255,0.25),
        inset -40px -10px 120px rgba(0,0,0,0.7);
    }
    .rsp-earth-img {
      position: absolute; top: 0; left: 0; width: 200%; height: 100%;
      background-size: 50% 100%;
      background-repeat: repeat-x;
      animation: rsp-earth-spin 30s linear infinite;
      filter: hue-rotate(-10deg) saturate(1.3) brightness(0.95);
      mix-blend-mode: screen;
      opacity: 0.95;
    }
    @keyframes rsp-earth-spin { from { transform: translateX(0); } to { transform: translateX(-50%); } }
    .rsp-globe-grid {
      position: absolute; inset: 0; border-radius: 50%;
      background:
        repeating-linear-gradient(0deg, rgba(0,220,255,0.18) 0 1px, transparent 1px 30px),
        repeating-linear-gradient(90deg, rgba(0,220,255,0.18) 0 1px, transparent 1px 30px);
      -webkit-mask-image: radial-gradient(circle, #000 60%, transparent 75%);
      mask-image: radial-gradient(circle, #000 60%, transparent 75%);
    }
    .rsp-globe-rim {
      position: absolute; inset: 0; border-radius: 50%;
      box-shadow: inset 0 0 60px 4px rgba(0,220,255,0.45);
    }
    .rsp-globe-outer-ring {
      position: absolute; inset: -4%; border-radius: 50%;
      border: 1px solid rgba(34,211,238,0.4);
    }
    .rsp-globe-outer-ring-dashed {
      position: absolute; inset: -10%; border-radius: 50%;
      border: 1px dashed rgba(34,211,238,0.15);
      animation: rsp-spin-slow 40s linear infinite;
    }
    @keyframes rsp-spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }

    /* ---------------- Logo hologram ---------------- */
    .rsp-logo-wrap {
      position: absolute; left: 50%; top: 50%;
      width: min(38vmin, 380px); height: min(38vmin, 380px);
      transform: translate(-50%, -50%) scale(0.75);
      opacity: 0;
      background: transparent; /* explicit — never let this box render opaque */
      transition: opacity 0.7s ease, transform 0.7s ease;
      z-index: 2;
      color: rgb(180, 30, 50);
      filter: drop-shadow(0 0 8px rgba(255,16,48,0.5)) drop-shadow(0 0 16px rgba(255,0,64,0.35));
    }
    #rsp-boot.rsp-phase-3 .rsp-logo-wrap { opacity: 1; transform: translate(-50%, -50%) scale(1); }
    #rsp-boot.rsp-phase-4 .rsp-logo-wrap {
      color: rgb(0, 160, 180);
      filter: drop-shadow(0 0 7px rgba(0,229,255,0.5)) drop-shadow(0 0 14px rgba(0,180,255,0.35));
      transition: color 1.2s ease, filter 1.2s ease, opacity 0.7s ease, transform 0.7s ease;
    }
    .rsp-logo-svg { width: 100%; height: 100%; display: block; overflow: visible; background: transparent; }
    .rsp-logo-img {
      width: 100%; height: 100%; object-fit: contain;
      mix-blend-mode: screen;
      filter: brightness(0) saturate(100%) invert(20%) sepia(99%) saturate(7480%) hue-rotate(346deg) brightness(62%) contrast(110%) drop-shadow(0 0 6px rgba(255,16,48,0.45)) drop-shadow(0 0 13px rgba(255,0,64,0.3));
      transition: filter 1.2s ease;
    }
    #rsp-boot.rsp-phase-4 .rsp-logo-img {
      filter: brightness(0) saturate(100%) invert(76%) sepia(91%) saturate(2438%) hue-rotate(140deg) brightness(68%) contrast(96%) drop-shadow(0 0 7px rgba(0,229,255,0.45)) drop-shadow(0 0 16px rgba(0,180,255,0.3));
    }
    /* ---------------- Reticle ---------------- */
    .rsp-reticle {
      position: absolute; left: 50%; top: 50%;
      width: 64px; height: 48px;
      transform: translate(-50%, -50%);
      opacity: 0; transition: opacity 0.3s ease;
      z-index: 5; pointer-events: none;
    }
    #rsp-boot.rsp-phase-1 .rsp-reticle { opacity: 1; }
    .rsp-reticle-box {
      position: absolute; inset: 0;
      border: 1px solid rgba(255, 32, 64, 0.8);
      box-shadow: 0 0 10px #ff2040, inset 0 0 8px #ff2040;
    }
    .rsp-reticle-dot {
      position: absolute; left: 50%; top: 50%;
      width: 8px; height: 8px; margin: -4px 0 0 -4px;
      border-radius: 50%; background: #fff;
      box-shadow: 0 0 12px #fff, 0 0 24px #ff4060;
    }
    .rsp-reticle-label {
      position: absolute; top: -14px; left: 0;
      font-size: 8px; color: #ff6070; letter-spacing: 0.1em;
    }

    /* ---------------- Title ---------------- */
    .rsp-boot-title-wrap {
      position: absolute; left: 50%; top: 6%;
      transform: translate(-50%, -16px);
      opacity: 0;
      transition: opacity 0.7s ease, transform 0.7s ease;
      z-index: 5; text-align: center;
    }
    #rsp-boot.rsp-phase-4 .rsp-boot-title-wrap { opacity: 1; transform: translate(-50%, 0); }
    .rsp-boot-title {
      margin: 0;
      font-size: clamp(24px, 5vw, 48px);
      font-weight: 900;
      letter-spacing: 0.4em;
      color: #e8feff;
      text-shadow: 0 0 12px #00e5ff, 0 0 28px #0078ff, 0 0 60px #0055ff;
    }
    .rsp-boot-title-rule {
      margin: 8px auto 0; height: 1px; width: 100%;
      background: linear-gradient(90deg, transparent, #22d3ee, transparent);
    }

    /* ---------------- Status + progress ---------------- */
    .rsp-boot-status {
      position: absolute; left: 50%; bottom: 10%; transform: translateX(-50%);
      width: min(560px, 80vw);
      opacity: 0; transition: opacity 0.5s ease;
      z-index: 5;
    }
    #rsp-boot.rsp-phase-3 .rsp-boot-status { opacity: 1; }
    .rsp-boot-status-top {
      display: flex; justify-content: space-between; align-items: baseline;
      margin-bottom: 8px;
      font-size: 10px; letter-spacing: 0.3em; color: rgba(165,243,252,0.9);
    }
    .rsp-boot-label { text-shadow: 0 0 8px #00e5ff; }
    .rsp-boot-bar-track {
      position: relative; width: 100%; height: 8px;
      background: rgba(8,51,68,0.4);
      border: 1px solid rgba(34,211,238,0.5);
      box-shadow: 0 0 10px rgba(0,229,255,0.4), inset 0 0 6px rgba(0,229,255,0.3);
      overflow: hidden;
    }
    .rsp-boot-bar-fill {
      position: absolute; inset-block: 0; left: 0; width: 0%;
      background: linear-gradient(90deg, #22d3ee 0%, #67e8f9 60%, #f87171 100%);
      box-shadow: 0 0 12px #00e5ff;
      transition: width 100ms linear;
    }
    .rsp-boot-bar-ticks {
      position: absolute; inset: 0;
      background-image: repeating-linear-gradient(90deg, rgba(0,0,0,0.4) 0 4px, transparent 4px 8px);
    }
    .rsp-boot-status-bottom {
      display: flex; justify-content: space-between;
      margin-top: 8px;
      font-size: 8px; color: rgba(34,211,238,0.6); letter-spacing: 0.05em;
    }

    /* ---------------- HUD corners ---------------- */
    .rsp-hud-corner {
      position: absolute; width: 64px; height: 64px;
      opacity: 0; transition: opacity 0.5s ease;
      z-index: 5; pointer-events: none;
    }
    #rsp-boot.rsp-phase-4 .rsp-hud-corner { opacity: 1; }
    .rsp-hud-tl { top: 24px; left: 24px; border-top: 2px solid #ef4444; border-left: 2px solid #ef4444; box-shadow: 0 0 12px #ff1040; }
    .rsp-hud-br { bottom: 24px; right: 24px; border-bottom: 2px solid #ef4444; border-right: 2px solid #ef4444; box-shadow: 0 0 12px #ff1040; }
    .rsp-hud-tr { top: 24px; right: 24px; border-top: 2px solid #22d3ee; border-right: 2px solid #22d3ee; box-shadow: 0 0 12px #00e5ff; }
    .rsp-hud-bl { bottom: 24px; left: 24px; border-bottom: 2px solid #22d3ee; border-left: 2px solid #22d3ee; box-shadow: 0 0 12px #00e5ff; }
  `;
  document.head.appendChild(s);
}
